using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed.
            // EF9 writes "$type" by default; existing 500K docs use "Discriminator"
            // and direct SQL queries reference c.Discriminator.
            // Fix: keep the legacy JSON property name.
            b.HasDiscriminator<string>("Discriminator")
             .HasValue<Product>("Product");

            // BREAKING CHANGE 2 — id value no longer includes discriminator prefix.
            // EF8 wrote id = "Product|123"; EF9 default is id = "123".
            // This generator restores the legacy format for new writes.
            // NOTE: FindAsync also constructs the id from the key — see
            // LegacyCosmosIdGenerator summary for the full impact.
            b.Property<string>("__id")
             .HasValueGenerator<LegacyCosmosIdGenerator>();

            // BREAKING CHANGE 3 — HasIndex() now throws.
            // EF8 silently ignored it; Cosmos DB indexes are managed server-side.
            // REMOVED: b.HasIndex(p => p.Sku);
        });
    }
}

/// <summary>
/// Restores the EF Core 8 id format ("Discriminator|Key") so new documents are
/// written with the same id shape as the existing 500K documents.
///
/// IMPORTANT — This generator only controls value creation for new/modified entities.
/// FindAsync(123) still constructs the id as "123" (EF9 default) and will NOT match
/// existing documents whose id is "Product|123".
///
/// Mitigation options:
///   1. Use LINQ queries instead of FindAsync for existing data.
///   2. Migrate all 500K documents to the new id format (remove the prefix).
///   3. Wrap FindAsync in a helper: FindByLegacyId("Product|" + id).
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
    {
        var discriminator = entry.Metadata.GetDiscriminatorValue();
        var key = entry.Property("Id").CurrentValue;
        return $"{discriminator}|{key}";
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; }
}

